function DocsSidebar({ onSearch } = {}) {
  const { div, nav, span, button, kbd } = tags;
  const route = useRoute();

  const sections = [
    { id: 'start', label: 'Start Here', highlight: true, items: [
      { id: 'quick-setup', label: 'Quick Setup', path: '/docs/quick-setup', icon: 'zap' },
      { id: 'first-prompt', label: 'First Prompt', path: '/docs/first-prompt', icon: 'message-square' }
    ]},
    { id: 'building', label: 'Building', collapsible: true, items: [
      { id: 'pages', label: 'Adding Pages', path: '/docs/building/pages', icon: 'file' }
    ]}
  ];

  return div({ class: css('_flex _col _h100 _bgbg') },
    // Search trigger
    div({ class: css('_px3 _pt3 _pb2') },
      button({ class: css('_flex _aic _gap2 _w100 _px3 _py2 _r1 _bgmuted/30 _border _bcborder/50'), onclick: onSearch },
        icon('search', { size: '14px' }),
        span({ class: css('_textsm _fgmutedfg _flex1 _textl') }, 'Search...'),
        kbd({ class: css('_px1 _r1 _bgmuted _textsm') }, '⌘K')
      )
    ),
    // Navigation
    nav({ class: css('_flex _col _gap1 _py2 _px2 _flex1 _overflow[auto]') },
      ...sections.map(section => {
        const [isOpen, setIsOpen] = createSignal(!section.collapsible);
        return div({ class: css('_flex _col') },
          div({ class: css('_flex _aic _jcsb _px2 _py1 _cursor[pointer]'), onclick: () => section.collapsible && setIsOpen(!isOpen()) },
            span({ class: css(`_caption _uppercase _ls[0.06em] ${section.highlight ? '_fgprimary' : '_fgmutedfg'}`) }, section.label),
            section.collapsible && icon('chevron-right', { size: '14px', class: css('_fgmutedfg') })
          ),
          div({ class: css('_flex _col _gap0'), style: isOpen() ? '' : 'display:none' },
            ...section.items.map(item => link({ href: item.path, class: css('_flex _aic _gap2 _px3 _py2 _r1 _textsm _nounder _fgmutedfg _hover:bgmuted/30') },
              icon(item.icon, { size: '16px' }),
              span(item.label)
            ))
          )
        );
      })
    )
  );
}
